class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> sequence;
        backtrack(num, sequence, 0);
        return sequence;
    }

    bool backtrack(const string& num, vector<int>& sequence, int start) {
        if (start == num.size() && sequence.size() >= 3) {
            return true;
        }
        for (int i = start; i < num.size(); ++i) {
            if (i > start && num[start] == '0') {
                break;
            }
            long long value = stoll(num.substr(start, i - start + 1));
            if (value > INT_MAX) {
                break;
            }
            int size = sequence.size();
            if (size >= 2 && value > (long long)sequence[size - 1] + sequence[size - 2]) {
                break;
            }
            if (size < 2 || value == (long long)sequence[size - 1] + sequence[size - 2]) {
                sequence.push_back((int)value);
                if (backtrack(num, sequence, i + 1)) {
                    return true;
                }
                sequence.pop_back();
            }
        }
        return false;
    }
};
